def parse_amount(raw: str) -> float:
    amount = float(raw.strip().replace(" ", "").replace(",", "."))
    if amount < 0:
        raise ValueError("Сумма не может быть отрицательной")
    return round(amount, 2)


def parse_bank_1c_date(raw: str) -> date:
    raw = raw.strip()
    for fmt in ("%d.%m.%Y", "%Y-%m-%d", "%d-%m-%Y"):
        try:
            return datetime.strptime(raw, fmt).date()
        except ValueError:
            continue
    raise ValueError("В выписке найдена дата в неизвестном формате")


def parse_bank_1c_amount(raw: str) -> float:
    cleaned = raw.strip().replace("\xa0", "").replace(" ", "").replace(",", ".")
    if not cleaned:
        raise ValueError("В выписке есть платеж без суммы")
    amount = float(cleaned)
    if amount <= 0:
        raise ValueError("В выписке есть платеж с некорректной суммой")
    return round(amount, 2)


def parse_bank_1c_balance_amount(raw: str) -> float:
    cleaned = raw.strip().replace("\xa0", "").replace(" ", "").replace(",", ".")
    if not cleaned:
        return 0.0
    return round(float(cleaned), 2)


def decode_bank_1c_export(data: bytes) -> str:
    if not data:
        raise ValueError("Файл выписки пустой")
    for encoding in ("cp1251", "utf-8-sig", "utf-8"):
        try:
            text = data.decode(encoding)
        except UnicodeDecodeError:
            continue
        if "1CClientBankExchange" in text:
            return text
    raise ValueError("Не удалось прочитать выписку. Нужен TXT 1С в кодировке WIN")


def parse_bank_1c_export(data: bytes) -> tuple[dict[str, str], list[dict[str, str]], list[dict[str, str]]]:
    text = decode_bank_1c_export(data)
    lines = [line.strip().lstrip("\ufeff") for line in text.splitlines()]
    first_line = next((line for line in lines if line), "")
    if first_line != "1CClientBankExchange":
        raise ValueError("Это не выгрузка 1С Клиент-Банк")

    meta: dict[str, str] = {}
    documents: list[dict[str, str]] = []
    account_sections: list[dict[str, str]] = []
    current: dict[str, str] | None = None
    current_account: dict[str, str] | None = None
    raw_lines: list[str] = []
    for line in lines[1:]:
        if not line:
            continue
        if line == "СекцияРасчСчет":
            current_account = {}
            continue
        if line == "КонецРасчСчет" and current_account is not None:
            account_sections.append(current_account)
            current_account = None
            continue
        if current_account is not None:
            if "=" in line:
                key, value = line.split("=", 1)
                current_account[key.strip()] = value.strip()
            continue
        if line.startswith("СекцияДокумент="):
            current = {"СекцияДокумент": line.split("=", 1)[1].strip()}
            raw_lines = [line]
            continue
        if line == "КонецДокумента" and current is not None:
            current["raw_import_text"] = "\n".join(raw_lines + [line])
            documents.append(current)
            current = None
            raw_lines = []
            continue
        if current is not None:
            raw_lines.append(line)
            if "=" in line:
                key, value = line.split("=", 1)
                current[key.strip()] = value.strip()
            continue
        if "=" in line:
            key, value = line.split("=", 1)
            meta.setdefault(key.strip(), value.strip())

    if meta.get("ВерсияФормата", "").strip() != "1.03":
        raise ValueError("Поддерживается только формат 1С 1.03")
    if not meta.get("РасчСчет", "").strip():
        raise ValueError("В выписке не найден расчетный счет")
    return meta, documents, account_sections


def bank_1c_expense_hash(document: dict[str, str]) -> str:
    parts = [
        document.get("Дата", ""),
        document.get("ДатаСписано", ""),
        document.get("Номер", ""),
        document.get("Сумма", ""),
        document.get("ПлательщикСчет", ""),
        document.get("ПлательщикРасчСчет", ""),
        document.get("ПолучательСчет", ""),
        document.get("ПолучательРасчСчет", ""),
        document.get("ПолучательИНН", ""),
        document.get("НазначениеПлатежа", ""),
    ]
    normalized = "\n".join(part.strip().casefold() for part in parts)
    return hashlib.sha256(normalized.encode("utf-8")).hexdigest()


@dataclass
class BankStatementImportResult:
    imported_count: int = 0
    duplicate_count: int = 0
    skipped_count: int = 0
    balance_count: int = 0


def import_bank_1c_statement(
    storage: Storage,
    owner_chat_id: int,
    data: bytes,
    created_by_user_id: int | None = None,
    created_by_name: str = "Импорт выписки",
) -> BankStatementImportResult:
    meta, documents, account_sections = parse_bank_1c_export(data)
    statement_account = meta.get("РасчСчет", "").strip()
    result = BankStatementImportResult()
    for account_section in account_sections:
        try:
            account_number = account_section.get("РасчСчет", "").strip() or statement_account
            balance_date_raw = account_section.get("ДатаКонца", "").strip() or account_section.get("ДатаНачала", "").strip()
            if not account_number or not balance_date_raw:
                continue
            storage.upsert_bank_account_balance(
                owner_chat_id,
                account_number,
                parse_bank_1c_date(balance_date_raw),
                parse_bank_1c_balance_amount(account_section.get("НачальныйОстаток", "")),
                parse_bank_1c_balance_amount(account_section.get("ВсегоСписано", "")),
                parse_bank_1c_balance_amount(account_section.get("ВсегоПоступило", "")),
                parse_bank_1c_balance_amount(account_section.get("КонечныйОстаток", "")),
            )
            result.balance_count += 1
        except ValueError:
            continue
    actor_name = created_by_name.strip() or "Импорт выписки"
    for document in documents:
        payer_accounts = {
            document.get("ПлательщикСчет", "").strip(),
            document.get("ПлательщикРасчСчет", "").strip(),
        }
        recipient_accounts = {
            document.get("ПолучательСчет", "").strip(),
            document.get("ПолучательРасчСчет", "").strip(),
        }
        is_expense = statement_account in payer_accounts and bool(document.get("ДатаСписано", "").strip())
        is_income = statement_account in recipient_accounts and bool(document.get("ДатаПоступило", "").strip())
        if not is_expense and not is_income:
            result.skipped_count += 1
            continue
        import_hash = bank_1c_expense_hash(document)
        if storage.expense_import_hash_exists(owner_chat_id, import_hash):
            result.duplicate_count += 1
            continue
        operation_date = parse_bank_1c_date(
            (document.get("ДатаСписано", "") if is_expense else document.get("ДатаПоступило", "")).strip()
            or document.get("Дата", "").strip()
        )
        amount = parse_bank_1c_amount(document.get("Сумма", ""))
        title = (
            document.get("Получатель", "").strip() or document.get("ПолучательСчет", "").strip() or "Расход из выписки"
            if is_expense
            else document.get("Плательщик", "").strip() or document.get("ПлательщикСчет", "").strip() or "Поступление из выписки"
        )
        purpose = document.get("НазначениеПлатежа", "").strip()
        doc_number = document.get("Номер", "").strip()
        doc_kind = document.get("СекцияДокумент", "").strip()
        comment_parts = []
        if purpose:
            comment_parts.append(purpose)
        doc_label = " ".join(part for part in (doc_kind, f"№ {doc_number}" if doc_number else "") if part)
        if doc_label:
            comment_parts.append(doc_label)
        try:
            storage.add_expense_entry(
                owner_chat_id,
                operation_date,
                "admin",
                "other" if is_expense else "income_unallocated",
                title,
                amount,
                " | ".join(comment_parts),
                "bank",
                True,
                created_by_user_id,
                actor_name,
                import_source="1c_bank",
                import_hash=import_hash,
                import_doc_number=doc_number,
                import_counterparty_inn=(document.get("ПолучательИНН", "") if is_expense else document.get("ПлательщикИНН", "")).strip(),
                import_counterparty_account=(
                    document.get("ПолучательСчет", "").strip() or document.get("ПолучательРасчСчет", "").strip()
                    if is_expense
                    else document.get("ПлательщикСчет", "").strip() or document.get("ПлательщикРасчСчет", "").strip()
                ),
                raw_import_text=document.get("raw_import_text", ""),
                operation_type="expense" if is_expense else "income",
            )
        except sqlite3.IntegrityError:
            result.duplicate_count += 1
            continue
        result.imported_count += 1
    return result


def hash_password(password: str, salt: str | None = None) -> str:
    salt = salt or secrets.token_hex(16)
    derived = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt.encode("utf-8"), 200_000)
    return f"{salt}${derived.hex()}"


def verify_password(password: str, stored_hash: str) -> bool:
    if not stored_hash or "$" not in stored_hash:
        return False
    salt, expected = stored_hash.split("$", 1)
    return hash_password(password, salt) == f"{salt}${expected}"


def generated_cash_vapid_key_paths(storage: Storage) -> tuple[Path, Path]:
    key_dir = storage.db_path.parent / "cash_push_keys"
    return key_dir / "private_key.pem", key_dir / "public_key.txt"


def ensure_generated_cash_vapid_keys(storage: Storage) -> tuple[str, str]:
    private_path, public_path = generated_cash_vapid_key_paths(storage)
    if private_path.exists() and public_path.exists():
        public_key = public_path.read_text(encoding="utf-8").strip()
        if public_key:
            return public_key, str(private_path)
    private_path.parent.mkdir(parents=True, exist_ok=True)
    public_der_path = private_path.with_name("public_key.der")
    subprocess.run(
        ["openssl", "ecparam", "-name", "prime256v1", "-genkey", "-noout", "-out", str(private_path)],
        check=True,
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
    )
    private_path.chmod(0o600)
    subprocess.run(
        ["openssl", "ec", "-in", str(private_path), "-pubout", "-outform", "DER", "-out", str(public_der_path)],
        check=True,
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
    )
    public_der = public_der_path.read_bytes()
    public_point = public_der[-65:]
    if len(public_point) != 65 or public_point[0] != 0x04:
        raise ValueError("Не удалось создать VAPID public key")
    public_key = base64.urlsafe_b64encode(public_point).decode("ascii").rstrip("=")
    public_path.write_text(public_key, encoding="utf-8")
    public_der_path.unlink(missing_ok=True)
    return public_key, str(private_path)


def cash_push_public_key(storage: Storage | None = None) -> str:
    configured = os.getenv("CASH_PUSH_VAPID_PUBLIC_KEY", os.getenv("VAPID_PUBLIC_KEY", "")).strip()
    if configured:
        return configured
    if storage is None:
        return ""
    try:
        public_key, _private_key = ensure_generated_cash_vapid_keys(storage)
    except Exception:
        return ""
    return public_key


def cash_push_private_key(storage: Storage | None = None) -> str:
    raw_key = os.getenv("CASH_PUSH_VAPID_PRIVATE_KEY", os.getenv("VAPID_PRIVATE_KEY", "")).strip()
    if raw_key.startswith("-----BEGIN") or "\\n" in raw_key:
        pem_key = raw_key.replace("\\n", "\n")
        key_path = Path(os.getenv("TMPDIR", "/tmp")) / "cash_vapid_private_key.pem"
        try:
            key_path.write_text(pem_key, encoding="utf-8")
            key_path.chmod(0o600)
            return str(key_path)
        except OSError:
            return raw_key
    if raw_key:
        return raw_key
    if storage is None:
        return ""
    try:
        _public_key, private_key = ensure_generated_cash_vapid_keys(storage)
    except Exception:
        return ""
    return private_key


def cash_push_enabled(storage: Storage | None = None) -> bool:
    return bool(cash_push_public_key(storage) and cash_push_private_key(storage))


def parse_cookies(environ) -> dict[str, str]:
    raw = environ.get("HTTP_COOKIE", "")
    if not raw:
        return {}
    cookie = SimpleCookie()
    cookie.load(raw)
    return {key: morsel.value for key, morsel in cookie.items()}


def parse_optional_number(raw: str) -> float | None:
    cleaned = raw.strip().replace(" ", "").replace(",", ".")
    if cleaned == "":
        return None
    return round(float(cleaned), 2)


def validate_auction_number(raw: str) -> str:
    normalized = raw.strip()
    if not normalized:
        raise ValueError("Нужно указать номер аукциона")
    if not normalized.isdigit():
        raise ValueError("В номере аукциона должны быть только цифры")
    return normalized


def auction_min_amount(total_amount: float, discount_percent: float) -> float:
    return round(total_amount * (1 - discount_percent / 100), 2)


def is_auction_archived(item) -> bool:
    if is_auction_deleted(item):
        return False
    if item.submit_decision_status == "rejected":
        return True
    return item.result_status in {"recognized_winner", "lost", "rejected"}


def is_auction_deleted(item) -> bool:
    return item.deleted_at is not None


def status_badge(status: str) -> str:
    label, css = STATUS_META.get(status, STATUS_META["not_started"])
    return f'<span class="{css}">{escape(label)}</span>'


def owner_options(storage: Storage) -> list[int]:
    with storage.connection() as conn:
        rows = conn.execute(
            """
            SELECT owner_id
            FROM (
                SELECT DISTINCT chat_id AS owner_id FROM contracts
                UNION
                SELECT DISTINCT owner_chat_id AS owner_id FROM auctions
            )
            ORDER BY owner_id ASC
            """
        ).fetchall()
    return [int(row["owner_id"]) for row in rows]


def pick_owner(storage: Storage, requested_owner: str | None) -> int | None:
    owners = owner_options(storage)
    if not owners:
        return None
    if requested_owner:
        try:
            parsed = int(requested_owner)
        except ValueError:
            parsed = None
        if parsed in owners:
            return parsed
    return owners[0]


def parse_month_key(raw: str | None) -> date | None:
    if not raw:
        return None
    raw = raw.strip()
    try:
        return date.fromisoformat(f"{raw}-01")
    except ValueError:
        return None


def contract_payload(storage: Storage, owner_chat_id: int) -> list[dict]:
    contracts = storage.list_contracts(owner_chat_id)
    payload: list[dict] = []
    for contract in contracts:
        stages = storage.list_stages_for_contract(owner_chat_id, contract.id)
        payments = storage.list_payments_for_contract(owner_chat_id, contract.id)
        total_amount = sum(stage.amount for stage in stages)
        paid_amount = sum(payment.amount for payment in payments)
        debt_amount = max(total_amount - paid_amount, 0.0)
        paid_ratio = (paid_amount / total_amount) if total_amount > 0 else 0.0
        advance_amount = round(total_amount * (contract.advance_percent or 0) / 100, 2) if total_amount > 0 else 0.0
        overdue_stages = sum(1 for stage in stages if stage.end_date < date.today())
        first_stage_start_date = next((stage.start_date for stage in stages if stage.start_date is not None), None)
        payload.append(
            {
                "contract": contract,
                "stages": stages,
                "payments": payments,
                "total_amount": total_amount,
                "paid_amount": paid_amount,
                "debt_amount": debt_amount,
                "paid_ratio": paid_ratio,
                "advance_amount": advance_amount,
                "overdue_stages": overdue_stages,
                "first_stage_start_date": first_stage_start_date,
            }
        )
    return payload


def permission_sections() -> list[tuple[str, str]]:
    return [(section_id, SECTION_LABELS[section_id]) for section_id in WEB_SECTION_IDS]


def parse_permissions(form: dict[str, str]) -> dict[str, dict[str, bool]]:
    permissions: dict[str, dict[str, bool]] = {}
    for section_id in WEB_SECTION_IDS:
        can_view = form.get(f"view_{section_id}") == "on"
        can_edit = form.get(f"edit_{section_id}") == "on"
        permissions[section_id] = {
            "can_view": can_view or can_edit,
            "can_edit": can_edit,
        }
    return permissions


def permission_summary(permissions: dict[str, dict[str, bool]]) -> str:
    enabled = [
        label
        for section_id, label in permission_sections()
        if permissions.get(section_id, {}).get("can_view")
    ]
    return ", ".join(enabled) if enabled else "Нет доступных разделов"


