def jurisprudence_contract_options(storage: Storage, owner_chat_id: int) -> list[tuple[str, str]]:
    options: list[tuple[str, str]] = []
    for contract in storage.list_contracts(owner_chat_id):
        label = contract.object_name.strip() or contract.title
        options.append((str(contract.id), label))
    return options


def jurisprudence_object_options(storage: Storage, owner_chat_id: int) -> list[str]:
    def clean_label(value: str) -> str:
        normalized = value.strip()
        if normalized.startswith("label:"):
            normalized = normalized.split(":", 1)[1].strip()
        return normalized

    labels = set()
    for _, label in jurisprudence_contract_options(storage, owner_chat_id):
        cleaned = clean_label(label)
        if cleaned:
            labels.add(cleaned)
    for label in storage.list_jurisprudence_objects(owner_chat_id):
        cleaned = clean_label(label)
        if cleaned:
            labels.add(cleaned)
    return sorted(labels, key=lambda value: value.lower())


def jurisprudence_object_filter_options(storage: Storage, owner_chat_id: int) -> list[tuple[str, str]]:
    options: list[tuple[str, str]] = []
    seen_values: set[str] = set()
    contract_labels = set()
    for contract_id, label in jurisprudence_contract_options(storage, owner_chat_id):
        value = f"contract:{contract_id}"
        contract_labels.add(label.strip())
        if value not in seen_values:
            options.append((value, label))
            seen_values.add(value)
    for label in jurisprudence_object_options(storage, owner_chat_id):
        normalized_label = label.strip()
        if not normalized_label or normalized_label in contract_labels:
            continue
        value = f"label:{normalized_label}"
        if value not in seen_values:
            options.append((value, normalized_label))
            seen_values.add(value)
    return options


def resolve_jurisprudence_filter_label(storage: Storage, owner_chat_id: int, object_filter: str) -> str:
    raw_filter = object_filter.strip()
    if not raw_filter:
        return ""
    for value, label in jurisprudence_object_filter_options(storage, owner_chat_id):
        if value == raw_filter:
            return label
    if raw_filter.startswith("label:"):
        return raw_filter.split(":", 1)[1].strip()
    if raw_filter.startswith("contract:"):
        contract_id_raw = raw_filter.split(":", 1)[1].strip()
        for contract_id, label in jurisprudence_contract_options(storage, owner_chat_id):
            if contract_id == contract_id_raw:
                return label
    return raw_filter


def normalize_legal_letter_object_label(object_label: str) -> str:
    normalized = object_label.strip()
    if normalized.startswith("label:"):
        normalized = normalized.split(":", 1)[1].strip()
    return normalized


def compact_object_match_key(value: str) -> str:
    return re.sub(r"[\W_]+", "", normalize_legal_letter_object_label(value).replace("ё", "е").lower())


def quoted_object_part(value: str) -> str:
    normalized = normalize_legal_letter_object_label(value)
    if "«" in normalized and "»" in normalized:
        quoted = normalized.split("«", 1)[1].split("»", 1)[0].strip()
        if quoted:
            return quoted
    return ""


def resolve_jurisprudence_object_record(storage: Storage, owner_chat_id: int, object_label: str, contract=None):
    candidates = storage.list_jurisprudence_object_records(owner_chat_id)
    labels_to_match = [normalize_legal_letter_object_label(object_label)]
    if contract is not None:
        labels_to_match.append((contract.object_name.strip() or contract.title.strip() or "").strip())
    normalized_labels = [label for label in labels_to_match if label]
    normalized_keys = [compact_object_match_key(label) for label in normalized_labels if compact_object_match_key(label)]
    for item in candidates:
        item_name = item.name.strip()
        if any(item_name.lower() == label.lower() for label in normalized_labels):
            return item
        item_short = quoted_object_part(item_name)
        if item_short and any(item_short.lower() == label.lower() for label in normalized_labels):
            return item
    for item in candidates:
        item_key = compact_object_match_key(item.name)
        item_short_key = compact_object_match_key(quoted_object_part(item.name))
        if any(
            key and (
                key == item_key
                or key == item_short_key
                or key in item_key
                or (item_key and item_key in key)
            )
            for key in normalized_keys
        ):
            return item
    return None


def resolve_contract_object_match(storage: Storage, owner_chat_id: int, object_label: str, contract=None):
    candidates = [contract] if contract is not None else storage.list_contracts(owner_chat_id)
    labels_to_match = [normalize_legal_letter_object_label(object_label)]
    normalized_labels = [label for label in labels_to_match if label]
    normalized_keys = [compact_object_match_key(label) for label in normalized_labels if compact_object_match_key(label)]
    for item in candidates:
        if item is None:
            continue
        item_name = (item.object_name.strip() or item.title.strip() or "").strip()
        if any(item_name.lower() == label.lower() for label in normalized_labels):
            return item
        item_short = quoted_object_part(item_name)
        if item_short and any(item_short.lower() == label.lower() for label in normalized_labels):
            return item
    for item in candidates:
        if item is None:
            continue
        item_name = (item.object_name.strip() or item.title.strip() or "").strip()
        item_key = compact_object_match_key(item_name)
        item_short_key = compact_object_match_key(quoted_object_part(item_name))
        if any(
            key and (
                key == item_key
                or key == item_short_key
                or key in item_key
                or (item_key and item_key in key)
            )
            for key in normalized_keys
        ):
            return item
    return None


def jurisprudence_letter_object_display(storage: Storage, owner_chat_id: int, letter, contract=None) -> tuple[str, str]:
    object_record = resolve_jurisprudence_object_record(storage, owner_chat_id, letter.object_label, contract)
    if object_record is not None:
        return object_record.name.strip(), object_record.customer.strip()
    contract_match = resolve_contract_object_match(storage, owner_chat_id, letter.object_label, contract)
    if contract_match is not None:
        return (
            contract_match.object_name.strip() or contract_match.title.strip() or letter.object_label.strip() or "Без объекта",
            contract_match.object_customer.strip(),
        )
    return normalize_legal_letter_object_label(letter.object_label) or "Без объекта", ""


def short_jurisprudence_object_label(object_label: str, contract=None) -> str:
    if contract is not None:
        return (contract.object_name.strip() or contract.title.strip() or object_label.strip() or "Без объекта").strip()
    normalized = normalize_legal_letter_object_label(object_label)
    if "«" in normalized and "»" in normalized:
        quoted = normalized.split("«", 1)[1].split("»", 1)[0].strip()
        if quoted:
            return quoted
    if "," in normalized:
        first_part = normalized.split(",", 1)[0].strip()
        if first_part:
            return first_part
    return normalized or "Без объекта"


def resolve_contract_id_by_object_label(storage: Storage, owner_chat_id: int, object_label: str) -> int | None:
    normalized_label = normalize_legal_letter_object_label(object_label).lower()
    if not normalized_label:
        return None
    for contract_id_raw, label in jurisprudence_contract_options(storage, owner_chat_id):
        if label.strip().lower() == normalized_label:
            try:
                return int(contract_id_raw)
            except (TypeError, ValueError):
                return None
    return None


def render_legal_letter_object_fields(
    storage: Storage,
    owner_chat_id: int,
    object_label: str,
) -> str:
    object_options = jurisprudence_object_options(storage, owner_chat_id)
    object_record = resolve_jurisprudence_object_record(storage, owner_chat_id, object_label)
    current_label = object_record.name if object_record is not None else normalize_legal_letter_object_label(object_label)
    if current_label and current_label not in object_options:
        object_options = [*object_options, current_label]
    object_options_html = "".join(
        f'<option value="{escape(label)}"{" selected" if label == current_label else ""}>{escape(label)}</option>'
        for label in object_options
    )
    return f"""
      <div class="field">
        <label>Объект</label>
        <select name="object_label" required>
          <option value="">Выберите объект</option>
          {object_options_html}
        </select>
      </div>
    """


def render_legal_letter_editor(
    storage: Storage,
    owner_chat_id: int,
    contract_id: int,
    letter,
    attachments: list,
    current_user: dict | None,
) -> str:
    subject_html = f'<div class="legal-letter-topic">{escape(letter.subject or "Без темы")}</div>'
    comment_html = f'<div class="contract-table-subtle">{escape(letter.comment)}</div>' if letter.comment else ''
    if not can_edit_legal_correspondence(current_user):
        return f"{subject_html}{comment_html}"
    attachment_html = "".join(
        f"""
        <div style="display:flex; align-items:center; justify-content:space-between; gap:10px; padding:8px 0; border-top:1px solid var(--line);">
          <a class="legal-letter-file" href="/contracts/letter-files/{attachment.id}/preview?owner={owner_chat_id}" target="_blank" rel="noopener">{escape(attachment.file_name or 'Файл')}</a>
          <form method="post" action="/contracts/letter-files/{attachment.id}/delete?owner={owner_chat_id}&contract_id={contract_id}">
            <button class="chip danger" type="submit">Удалить</button>
          </form>
        </div>
        """
        for attachment in attachments
    ) or '<div class="contract-table-subtle" style="padding-top:8px;">Файлов пока нет</div>'
    return f"""
    <details class="status-menu">
      <summary>
        {subject_html}
        {comment_html}
      </summary>
      <div class="status-popover" style="min-width:420px;">
        <form class="form-grid" method="post" action="/contracts/letters/{letter.id}/update?owner={owner_chat_id}&contract_id={contract_id}" enctype="multipart/form-data">
          <input type="hidden" name="contract_id" value="{letter.contract_id or contract_id}">
          <input type="hidden" name="object_label" value="{escape(letter.object_label)}">
          <div class="field">
            <label>Тип письма</label>
            <select name="direction" required>
              <option value="outgoing"{" selected" if letter.direction == "outgoing" else ""}>Исходящее</option>
              <option value="incoming"{" selected" if letter.direction == "incoming" else ""}>Входящее</option>
            </select>
          </div>
          <div class="field">
            <label>Канал</label>
            <select name="source_channel" required>
              <option value="mail"{" selected" if (letter.source_channel or "mail") == "mail" else ""}>Почта</option>
              <option value="eis"{" selected" if letter.source_channel == "eis" else ""}>ЕИС</option>
              <option value="courier"{" selected" if letter.source_channel == "courier" else ""}>Нарочно</option>
            </select>
          </div>
          <div class="field">
            <label>Дата письма</label>
            <input type="date" name="letter_date" value="{letter.letter_date.isoformat()}" required>
          </div>
          <div class="field" style="grid-column: 1 / -1;">
            <label>О чем письмо</label>
            <input type="text" name="subject" value="{escape(letter.subject)}" required>
          </div>
          <div class="field" style="grid-column: 1 / -1;">
            <label>Комментарий</label>
            <textarea name="comment">{escape(letter.comment)}</textarea>
          </div>
          <div class="field" style="grid-column: 1 / -1;">
            <label>Догрузить файлы</label>
            <input type="file" name="pdf_file" accept="application/pdf,.pdf,image/jpeg,.jpg,.jpeg,image/png,.png,application/msword,.doc,application/vnd.openxmlformats-officedocument.wordprocessingml.document,.docx" multiple>
          </div>
          <button class="submit-btn" type="submit">Сохранить письмо</button>
        </form>
        <div style="margin-top:14px;">
          <div class="contract-table-subtle" style="margin-top:0;">Вложения</div>
          {attachment_html}
        </div>
      </div>
    </details>
    """


def render_jurisprudence_letter_editor(storage: Storage, owner_chat_id: int, letter, attachments: list, current_user: dict | None) -> str:
    subject_html = f'<div class="legal-letter-topic">{escape(letter.subject or "Без темы")}</div>'
    comment_html = f'<div class="contract-table-subtle">{escape(letter.comment)}</div>' if letter.comment else ''
    if not can_edit_jurisprudence(current_user):
        return f"{subject_html}{comment_html}"
    attachment_html = "".join(
        f"""
        <div style="display:flex; align-items:center; justify-content:space-between; gap:10px; padding:8px 0; border-top:1px solid var(--line);">
          <a class="legal-letter-file" href="/contracts/letter-files/{attachment.id}/preview?owner={owner_chat_id}" target="_blank" rel="noopener">{escape(attachment.file_name or 'Файл')}</a>
          <form method="post" action="/contracts/letter-files/{attachment.id}/delete?owner={owner_chat_id}&next_path=/jurisprudence/letters">
            <button class="chip danger" type="submit">Удалить</button>
          </form>
        </div>
        """
        for attachment in attachments
    ) or '<div class="contract-table-subtle" style="padding-top:8px;">Файлов пока нет</div>'
    return f"""
    <details class="status-menu">
      <summary>
        {subject_html}
        {comment_html}
      </summary>
      <div class="status-popover" style="min-width:520px;">
        <form class="form-grid" method="post" action="/jurisprudence/letters/{letter.id}/update?owner={owner_chat_id}" enctype="multipart/form-data">
          {render_legal_letter_object_fields(storage, owner_chat_id, letter.object_label)}
          <div class="field">
            <label>Тип письма</label>
            <select name="direction" required>
              <option value="outgoing"{" selected" if letter.direction == "outgoing" else ""}>Исходящее</option>
              <option value="incoming"{" selected" if letter.direction == "incoming" else ""}>Входящее</option>
            </select>
          </div>
          <div class="field">
            <label>Канал</label>
            <select name="source_channel" required>
              <option value="mail"{" selected" if (letter.source_channel or "mail") == "mail" else ""}>Почта</option>
              <option value="eis"{" selected" if letter.source_channel == "eis" else ""}>ЕИС</option>
              <option value="courier"{" selected" if letter.source_channel == "courier" else ""}>Нарочно</option>
            </select>
          </div>
          <div class="field">
            <label>Дата письма</label>
            <input type="date" name="letter_date" value="{letter.letter_date.isoformat()}" required>
          </div>
          <div class="field" style="grid-column: 1 / -1;">
            <label>О чем письмо</label>
            <input type="text" name="subject" value="{escape(letter.subject)}" required>
          </div>
          <div class="field" style="grid-column: 1 / -1;">
            <label>Комментарий</label>
            <textarea name="comment">{escape(letter.comment)}</textarea>
          </div>
          <div class="field" style="grid-column: 1 / -1;">
            <label>Догрузить файлы</label>
            <input type="file" name="pdf_file" accept="application/pdf,.pdf,image/jpeg,.jpg,.jpeg,image/png,.png,application/msword,.doc,application/vnd.openxmlformats-officedocument.wordprocessingml.document,.docx" multiple>
          </div>
          <button class="submit-btn" type="submit">Сохранить письмо</button>
        </form>
        <div style="margin-top:14px;">
          <div class="contract-table-subtle" style="margin-top:0;">Вложения</div>
          {attachment_html}
        </div>
      </div>
    </details>
    """


