def local_contract_event_date(value: datetime) -> date:
    if value.tzinfo is None:
        return value.replace(tzinfo=timezone.utc).astimezone(VLADIVOSTOK_TZ).date()
    return value.astimezone(VLADIVOSTOK_TZ).date()


def contract_timeline_badge(item: dict) -> str:
    kind = item.get("kind", "")
    if kind == "legal_incoming":
        return '<span class="chip danger">Входящее</span>'
    if kind == "legal_outgoing":
        return '<span class="chip ok">Исходящее</span>'
    if kind == "meeting":
        return '<span class="chip warn">Встреча</span>'
    if kind == "meeting_update":
        return '<span class="chip">Изменение</span>'
    if kind == "construction_report":
        return '<span class="chip accent">Стройка</span>'
    if kind == "invoice":
        return '<span class="chip warn">Счет</span>'
    if kind == "stage_status":
        css = item.get("badge_css", "chip")
        label = item.get("badge_label", "Статус")
        return f'<span class="{escape(css)}">{escape(label)}</span>'
    if kind == "payment":
        return '<span class="chip ok">Оплата</span>'
    if kind == "letter_update":
        return '<span class="chip">Изменение</span>'
    if kind == "stage":
        return '<span class="chip">Этап</span>'
    return '<span class="chip">Событие</span>'


def build_contract_timeline_items(storage: Storage, owner_chat_id: int, contract_id: int) -> list[dict]:
    logged_events = storage.list_contract_events(owner_chat_id, contract_id)
    stages = storage.list_stages_for_contract(owner_chat_id, contract_id)
    legal_letters = storage.list_legal_letters_for_contract(owner_chat_id, contract_id)
    meetings = storage.list_contract_meetings_for_contract(owner_chat_id, contract_id)
    construction_reports = storage.list_construction_reports_for_contract(owner_chat_id, contract_id)
    payments = storage.list_payments_for_contract(owner_chat_id, contract_id)

    logged_refs = {
        (item.source_kind, item.source_ref)
        for item in logged_events
        if item.source_kind and item.source_ref
    }
    timeline_items: list[dict] = []

    for item in logged_events:
        timeline_items.append(
            {
                "sort_date": item.event_date,
                "title": item.title,
                "description": item.description,
                "actor_name": item.actor_name.strip() or "Автор неизвестен",
                "kind": item.event_type or "event",
                "badge_label": "Статус" if item.event_type == "stage_status" else "",
                "badge_css": "chip",
            }
        )

    for letter in legal_letters:
        source_ref = str(letter.id)
        if ("legal_letter_create", source_ref) in logged_refs:
            continue
        direction_label, badge_class = LEGAL_LETTER_META.get(letter.direction, LEGAL_LETTER_META["outgoing"])
        timeline_items.append(
            {
                "sort_date": letter.letter_date,
                "title": letter.subject.strip() or "Юридическое письмо",
                "description": letter.comment.strip(),
                "actor_name": letter.created_by_name.strip() or "Автор неизвестен",
                "kind": "legal_incoming" if letter.direction == "incoming" else "legal_outgoing",
                "badge_label": direction_label,
                "badge_css": badge_class,
            }
        )

    for meeting in meetings:
        source_ref = str(meeting.id)
        if ("contract_meeting_create", source_ref) in logged_refs:
            continue
        meeting_description = meeting.summary.strip()
        location = (meeting.location or "").strip()
        contractor_attendees = (meeting.contractor_attendees or meeting.attendees or "").strip()
        customer_attendees = (meeting.customer_attendees or "").strip()
        if location:
            meeting_description = f"{meeting_description}\nМесто встречи: {location}" if meeting_description else f"Место встречи: {location}"
        if contractor_attendees:
            meeting_description = f"{meeting_description}\nОт подрядчика: {contractor_attendees}" if meeting_description else f"От подрядчика: {contractor_attendees}"
        if customer_attendees:
            meeting_description = f"{meeting_description}\nОт заказчика: {customer_attendees}" if meeting_description else f"От заказчика: {customer_attendees}"
        timeline_items.append(
            {
                "sort_date": meeting.meeting_date,
                "title": "Встреча руководства",
                "description": meeting_description,
                "actor_name": meeting.created_by_name.strip() or "Автор неизвестен",
                "kind": "meeting",
                "badge_label": "Встреча",
                "badge_css": "chip warn",
            }
        )

    for payment in payments:
        source_ref = str(payment.id)
        if ("payment_create", source_ref) in logged_refs:
            continue
        timeline_items.append(
            {
                "sort_date": payment.payment_date,
                "title": f"Добавлена оплата по контракту на {format_amount(payment.amount)}",
                "description": "",
                "actor_name": "Автор неизвестен",
                "kind": "payment",
                "badge_label": "Оплата",
                "badge_css": "chip ok",
            }
        )

    for report in construction_reports:
        source_ref = str(report.id)
        if ("construction_report_create", source_ref) in logged_refs:
            continue
        description = report.work_description.strip()
        if report.day_comment.strip():
            description = f"{description}\nКомментарий дня: {report.day_comment.strip()}" if description else f"Комментарий дня: {report.day_comment.strip()}"
        timeline_items.append(
            {
                "sort_date": report.report_date,
                "title": f"Строительный отчет: {report.workers_count} рабочих",
                "description": description,
                "actor_name": report.created_by_name.strip() or "Автор неизвестен",
                "kind": "construction_report",
                "badge_label": "Стройка",
                "badge_css": "chip accent",
            }
        )

    for stage in stages:
        if stage.status_updated_at is not None and stage.status != "not_started":
            status_date = local_contract_event_date(stage.status_updated_at)
            status_ref = f"{stage.id}:{stage.status}:{status_date.isoformat()}"
            if ("stage_status", status_ref) not in logged_refs:
                status_label, status_css = STATUS_META.get(stage.status, ("Статус изменен", "chip"))
                timeline_items.append(
                    {
                        "sort_date": status_date,
                        "title": f"{stage.name}: {status_label}",
                        "description": "",
                        "actor_name": stage.status_updated_by_name.strip() or "Автор неизвестен",
                        "kind": "stage_status",
                        "badge_label": status_label,
                        "badge_css": status_css,
                    }
                )
        if stage.advance_invoice_issued and stage.advance_invoice_issued_at is not None:
            invoice_date = local_contract_event_date(stage.advance_invoice_issued_at)
            invoice_ref = f"{stage.id}:advance:1:{invoice_date.isoformat()}"
            if ("invoice_status", invoice_ref) not in logged_refs:
                timeline_items.append(
                    {
                        "sort_date": invoice_date,
                        "title": f"{stage.name}: выставлен счет на аванс",
                        "description": "",
                        "actor_name": stage.advance_invoice_issued_by_name.strip() or "Автор неизвестен",
                        "kind": "invoice",
                        "badge_label": "Счет",
                        "badge_css": "chip warn",
                    }
                )
        if stage.final_invoice_issued and stage.final_invoice_issued_at is not None:
            invoice_date = local_contract_event_date(stage.final_invoice_issued_at)
            invoice_ref = f"{stage.id}:final:1:{invoice_date.isoformat()}"
            if ("invoice_status", invoice_ref) not in logged_refs:
                timeline_items.append(
                    {
                        "sort_date": invoice_date,
                        "title": f"{stage.name}: выставлен счет на остаток",
                        "description": "",
                        "actor_name": stage.final_invoice_issued_by_name.strip() or "Автор неизвестен",
                        "kind": "invoice",
                        "badge_label": "Счет",
                        "badge_css": "chip warn",
                    }
                )

    timeline_items.sort(
        key=lambda item: (
            item["sort_date"],
            item["title"],
            item["description"],
            item["actor_name"],
        ),
        reverse=True,
    )
    return timeline_items


def render_contract_timeline_page(storage: Storage, owner_chat_id: int, contract_id: int, current_user: dict | None, flash_message: str = "") -> str:
    contract = storage.get_contract(owner_chat_id, contract_id)
    if contract is None:
        return '<div class="card panel"><div class="empty">Контракт не найден.</div></div>'

    object_name = contract.object_name.strip() or contract.title
    object_address = contract.object_address.strip()
    title_line = f"{object_name}, {object_address}" if object_address else object_name
    timeline_items = build_contract_timeline_items(storage, owner_chat_id, contract_id)
    flash_html = f'<div class="flash">{escape(flash_message)}</div>' if flash_message else ""
    export_link = f"/contracts/{contract_id}/timeline/export?owner={owner_chat_id}"
    rows_html = "".join(
        f"""
        <div class="timeline-item">
          <div class="timeline-date">{format_date(item["sort_date"])}</div>
          <div>
            <div style="margin-bottom:8px;">{contract_timeline_badge(item)}</div>
            <div class="timeline-title">{escape(item["title"])}</div>
            {f'<div class="contract-table-subtle" style="margin-bottom:6px;">{escape(item["description"])}</div>' if item["description"] else ''}
            <div class="contract-table-subtle">Ответственный: {escape(item["actor_name"])}</div>
          </div>
        </div>
        """
        for item in timeline_items
    ) or '<div class="empty">По контракту еще нет зафиксированных событий.</div>'

    return f"""
    <section class="card panel expenses-panel" style="margin-top:22px;">
      <div class="panel-head contract-detail-head">
        <div>
          <h2 class="panel-title">Хронология контракта</h2>
          <div class="panel-sub">{escape(title_line)}</div>
        </div>
        <a class="chip contract-back-link" href="/contracts/{contract_id}?owner={owner_chat_id}">← Назад к контракту</a>
      </div>
      <div class="info-row">
        <span class="chip">Событий: {len(timeline_items)}</span>
        <span class="chip">Контракт № {escape(contract.contract_number.strip() or 'Не указан')}</span>
        <a class="secondary-btn info-row-end" href="{export_link}">Выгрузить CSV</a>
      </div>
    </section>
    {flash_html}
    <section class="card panel" style="margin-top:22px;">
      <div class="panel-head">
        <div>
          <h2 class="panel-title">Хронология</h2>
          <div class="panel-sub">Единый журнал писем, статусов этапов, счетов и других действий по контракту.</div>
        </div>
      </div>
      <div class="timeline">{rows_html}</div>
    </section>
    """


def construction_workers_options(selected: int = 0) -> str:
    return "".join(
        f'<option value="{count}"{" selected" if count == selected else ""}>{count}</option>'
        for count in range(0, 51)
    )


def render_construction_report_editor(owner_chat_id: int, contract_id: int, report, current_user: dict | None) -> str:
    description_html = f'<div class="legal-letter-topic" style="white-space:pre-line;">{escape(report.work_description or "Без описания работ")}</div>'
    if report.day_comment:
        description_html += f'<div class="contract-table-subtle" style="white-space:pre-line;">{escape(report.day_comment)}</div>'
    if not can_edit_construction_reports(current_user):
        return description_html
    return f"""
    <details class="status-menu">
      <summary>{description_html}</summary>
      <div class="status-popover" style="min-width:520px;">
        <form class="form-grid" method="post" action="/contracts/construction-reports/{report.id}/update?owner={owner_chat_id}&contract_id={contract_id}">
          <div class="field">
            <label>Дата отчета</label>
            <input type="date" name="report_date" value="{report.report_date.isoformat()}" required>
          </div>
          <div class="field">
            <label>Рабочих на объекте</label>
            <select name="workers_count" required>
              {construction_workers_options(report.workers_count)}
            </select>
          </div>
          <div class="field" style="grid-column: 1 / -1;">
            <label>Выполненные работы</label>
            <textarea name="work_description" required>{escape(report.work_description)}</textarea>
          </div>
          <div class="field" style="grid-column: 1 / -1;">
            <label>Комментарий по дню</label>
            <textarea name="day_comment" placeholder="Полный день, 1/2 дня, погодные ограничения и т.д.">{escape(report.day_comment)}</textarea>
          </div>
          <button class="submit-btn" type="submit">Сохранить отчет</button>
        </form>
      </div>
    </details>
    """


def render_construction_report_photos(owner_chat_id: int, contract_id: int, report_id: int, photos: list, current_user: dict | None) -> str:
    if photos:
        slides_html = "".join(
            f'''
            <figure class="construction-photo-slide{" is-active" if index == 0 else ""}" data-construction-photo-slide="1">
              <img src="/contracts/construction-photos/{photo.id}/file?owner={owner_chat_id}" alt="{escape(photo.file_name or 'Фото отчета')}">
              <figcaption>{index + 1} / {len(photos)}</figcaption>
            </figure>
            '''
            for index, photo in enumerate(photos)
        )
        files_html = f"""
        <button class="secondary-btn construction-photo-view-btn" type="button" data-construction-carousel-open="construction-photos-{report_id}">
          Смотреть
          <span>{len(photos)}</span>
        </button>
        <div class="construction-photo-modal" data-construction-carousel-modal="construction-photos-{report_id}" aria-hidden="true">
          <div class="construction-photo-backdrop" data-construction-carousel-close="1"></div>
          <div class="construction-photo-dialog" role="dialog" aria-modal="true" aria-label="Фотографии строительного отчета">
            <button class="construction-photo-close" type="button" data-construction-carousel-close="1" aria-label="Закрыть">×</button>
            <button class="construction-photo-arrow construction-photo-arrow-left" type="button" data-construction-carousel-prev="1" aria-label="Предыдущее фото">←</button>
            <div class="construction-photo-stage" data-construction-carousel-stage="1">
              {slides_html}
            </div>
            <button class="construction-photo-arrow construction-photo-arrow-right" type="button" data-construction-carousel-next="1" aria-label="Следующее фото">→</button>
          </div>
        </div>
        """
    else:
        files_html = ""
    if not can_edit_construction_reports(current_user):
        return files_html
    return f"""
    {files_html}
    <details class="status-menu construction-photo-add-menu">
      <summary><span class="construction-photo-add-link">Добавить фото</span></summary>
      <div class="status-popover" style="min-width:360px;">
        <form class="form-grid" method="post" action="/contracts/construction-reports/{report_id}/photos/new?owner={owner_chat_id}&contract_id={contract_id}" enctype="multipart/form-data">
          <div class="field" style="grid-column: 1 / -1;">
            <label>Фотографии</label>
            <input type="file" name="report_photos" accept="image/jpeg,.jpg,.jpeg,image/png,.png,image/webp,.webp" multiple required>
          </div>
          <button class="submit-btn" type="submit">Загрузить фото</button>
        </form>
      </div>
    </details>
    """


